                var message = serializer.Deserialize<SimpleRequest>(new JsonTextReader(new StreamReader(ms)))!;

                ms.Seek(0, SeekOrigin.Begin);
                using (var writer = new JsonTextWriter(new StreamWriter(ms, Encoding.UTF8, 1024, true)))
