                    serializer.Serialize(writer, BenchmarkServiceImpl.CreateResponse(message));
                }

                context.Response.StatusCode = StatusCodes.Status200OK;

                ms.Seek(0, SeekOrigin.Begin);
                await ms.CopyToAsync(context.Response.Body);
            }

